const results = [];

for (const item of $input.all()) {
  const o = item.json;
  const billing = o.billing || {};
  const customerName = (billing.first_name + ' ' + billing.last_name).trim();
  const customerEmail = billing.email || '';
  const phone = billing.phone || '';
  const address = [billing.address_1, billing.address_2, billing.city, billing.postcode, billing.country].filter(Boolean).join(', ');
  const lineItems = (o.line_items || []).map(li => li.name + ' x' + li.quantity + ' €' + li.total).join(', ');
  const total = parseFloat(o.total) || 0;
  const payment = o.payment_method_title || '';
  const statusMap = { 'pending': 'Pending Payment', 'processing': 'Processing', 'on-hold': 'On Hold', 'completed': 'Completed', 'cancelled': 'Cancelled', 'refunded': 'Refunded', 'failed': 'Failed' };
  const orderStatus = statusMap[o.status] || o.status;
  const receivedAt = o.date_created ? new Date(o.date_created).toISOString() : new Date().toISOString();

  results.push({ json: {
    orderNum: '#' + o.number,
    Customer: customerName || '(unknown)',
    Email: customerEmail,
    Phone: phone,
    Address: address,
    Product: lineItems,
    Total: total,
    Payment: payment,
    Shipping: 'Besplatna dostava',
    Category: 'ORDER',
    Summary: orderStatus,
    Received: receivedAt
  }});
}

return results;
